async function c(a,n){const e=await fetch(a,n),s=(e.headers.get("content-type")||"").toLowerCase();if(!s.includes("application/json")){let t="";try{t=(await e.text()).slice(0,80)}catch{}throw new Error(`Server returned ${s||"non-JSON"} (HTTP ${e.status})${t?` — "${t.replace(/\s+/g," ").trim()}"`:""}`)}let r;try{r=await e.json()}catch(t){throw new Error(`Bad JSON from server (HTTP ${e.status}): ${t instanceof Error?t.message:t}`,{cause:t})}if(!e.ok){const t=r.detail,o=typeof t=="string"?t:t?JSON.stringify(t):`Request failed (HTTP ${e.status})`;throw new Error(o)}return r}export{c as fetchJson};
